using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_fd17fef9f14f499594c0250f67fd7e3f.Client;

namespace sv_fd17fef9f14f499594c0250f67fd7e3f;

/// <summary>
/// Server-side AuthenticationStateProvider that hardcodes a logged-in user
/// and persists the identity via PersistentComponentState so the WebAssembly
/// runtime can pick it up after prerendering.
/// </summary>
public sealed class PersistingAuthenticationStateProvider
    : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;
    private readonly Task<AuthenticationState> _authStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;

        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        _authStateTask = Task.FromResult(new AuthenticationState(user));

        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = principal.FindFirst(ClaimTypes.Email)!.Value,
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            });
        }
    }

    public void Dispose() => _subscription.Dispose();
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_fd17fef9f14f499594c0250f67fd7e3f.Client;

/// <summary>
/// Client-side (WebAssembly) AuthenticationStateProvider that reads the
/// persisted user info from PersistentComponentState (serialized during
/// server prerendering).
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (!persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo)
            || userInfo is null)
        {
            _authStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        _authStateTask = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

